external_knowledge:
- "core architects of knowledge" refers to researchers;
- "cast their shadows" metaphorically represents the idea of being cited;
- "more than half a decade" means more than five years ago;
- "blueprints" refers to papers;
- "depth of their footprint" refers to the cited count;
- "time of their inception" refers to the year of publication;
- "nature of their creation" refers to the document type;
- "houses that hosted their visions" refers to the publisher.

sql:
SELECT document_type, COUNT(*)
FROM papers
GROUP BY document_type;

SELECT AVG(paper_count) AS average_papers_per_year
FROM (
  SELECT COUNT(*) AS paper_count
  FROM papers
  GROUP BY year
) AS yearly_paper_counts;

SELECT paper_id, title, abstract, cited_count
FROM papers
WHERE cited_count = (SELECT MAX(cited_count) FROM papers);

SELECT AVG(citation_count) AS average_citations
FROM (
  SELECT paper_id, COUNT(*) AS citation_count
  FROM citations
  GROUP BY paper_id
) AS citation_counts;

external_knowledge:
- "unique, prolific authors" refers to authors who, despite having only one paper (unique), have made a significant impact; 
- "not-so-common influence" implies the paper has a citation count that is above average; 
- "significantly contributed to their field" indicates that the authors have an h-index greater than 10, reflecting their overall impact; 
- "citation count exceeding the usual citation average" means the citation count is above the average citation count of all papers in the database.

sql:
SELECT AVG(author_count) as average_author_count
FROM (
  SELECT paper_id, COUNT(*) as author_count
  FROM author_paper
  GROUP BY paper_id
) as author_counts;

SELECT institution_id, COUNT(author_id) AS author_count 
FROM author_institution 
GROUP BY institution_id;
